import json
import logging
import jsonschema

logger = logging.getLogger()
logger.setLevel(logging.INFO)

EVENT_SCHEMA = {
    "type": "object",
    "properties": {
        "action": {
            "type": "string",
            "enum": ["click", "purchase", "signup", "view", "logout"]
        },
        "user_id": {
            "type": "string",
            "pattern": "^[a-zA-Z0-9_-]{1,128}$"
        },
        "timestamp": {
            "type": "string",
            "format": "date-time"
        },
        "metadata": {
            "type": "object",
            "properties": {
                "source": {"type": "string", "maxLength": 256},
                "campaign_id": {"type": "string", "maxLength": 256},
                "item_id": {"type": "string", "maxLength": 256},
                "amount": {"type": "number", "minimum": 0, "maximum": 1000000}
            },
            "additionalProperties": False
        }
    },
    "required": ["action", "user_id", "timestamp"],
    "additionalProperties": False
}

MAX_PAYLOAD_SIZE = 1 * 1024 * 1024  # 1 MB


def validate_and_parse_payload(body):
    """Safely deserialize and validate the JSON payload.

    SECURITY NOTE: We use json.loads (not pickle) for deserialization of
    external/untrusted input. pickle.loads on untrusted data is a critical
    remote-code-execution vulnerability because pickle can execute arbitrary
    Python code during deserialization. JSON is a safe, data-only format.
    """
    if isinstance(body, bytes):
        body = body.decode("utf-8")

    if len(body) > MAX_PAYLOAD_SIZE:
        raise ValueError("Payload exceeds maximum allowed size")

    data = json.loads(body)

    jsonschema.validate(instance=data, schema=EVENT_SCHEMA)

    return data


def process_action(action_data):
    """Process a validated user action."""
    action = action_data["action"]
    user_id = action_data["user_id"]
    timestamp = action_data["timestamp"]
    metadata = action_data.get("metadata", {})

    logger.info(
        "Processing action=%s for user_id=%s at timestamp=%s",
        action, user_id, timestamp
    )

    result = {
        "action": action,
        "user_id": user_id,
        "timestamp": timestamp,
        "processed": True
    }

    if action == "purchase" and metadata.get("amount") is not None:
        result["amount"] = metadata["amount"]
        result["item_id"] = metadata.get("item_id")

    return result


def lambda_handler(event, context):
    """AWS Lambda handler triggered by API Gateway.

    Expects a JSON body from an external webhook partner.
    """
    try:
        body = event.get("body", "")
        if not body:
            return {
                "statusCode": 400,
                "headers": {"Content-Type": "application/json"},
                "body": json.dumps({"error": "Empty request body"})
            }

        if event.get("isBase64Encoded", False):
            import base64
            body = base64.b64decode(body).decode("utf-8")

        action_data = validate_and_parse_payload(body)

        result = process_action(action_data)

        return {
            "statusCode": 200,
            "headers": {"Content-Type": "application/json"},
            "body": json.dumps({
                "message": "Event processed successfully",
                "result": result
            })
        }

    except json.JSONDecodeError:
        logger.warning("Invalid JSON received")
        return {
            "statusCode": 400,
            "headers": {"Content-Type": "application/json"},
            "body": json.dumps({"error": "Invalid JSON payload"})
        }

    except jsonschema.ValidationError as e:
        logger.warning("Schema validation failed: %s", e.message)
        return {
            "statusCode": 400,
            "headers": {"Content-Type": "application/json"},
            "body": json.dumps({"error": f"Validation error: {e.message}"})
        }

    except ValueError as e:
        logger.warning("Value error: %s", str(e))
        return {
            "statusCode": 400,
            "headers": {"Content-Type": "application/json"},
            "body": json.dumps({"error": str(e)})
        }

    except Exception:
        logger.exception("Unexpected error processing webhook event")
        return {
            "statusCode": 500,
            "headers": {"Content-Type": "application/json"},
            "body": json.dumps({"error": "Internal server error"})
        }